import { useState, useEffect } from 'react';
import * as Location from 'expo-location';
import AsyncStorage from '@react-native-async-storage/async-storage';

interface LocationState {
  latitude: number;
  longitude: number;
}

interface UseLocationResult {
  location: LocationState | null;
  error: string | null;
}

const LOCATION_CACHE_KEY = 'user_location_cache';
const LOCATION_CACHE_DURATION = 10 * 60 * 1000; // 10 minutes

export const useLocation = (): UseLocationResult => {
  const [location, setLocation] = useState<LocationState | null>(null);
  const [error, setError] = useState<string | null>(null);

  const loadCachedLocation = async () => {
    try {
      const cached = await AsyncStorage.getItem(LOCATION_CACHE_KEY);
      if (cached) {
        const parsedLocation: LocationState = JSON.parse(cached);
        const now = Date.now();
        if (now - parsedLocation.timestamp < LOCATION_CACHE_DURATION) {
          setLocation(parsedLocation);
          return true;
        }
      }
    } catch (err) {
      console.warn('Error loading cached location:', err);
    }
    return false;
  };

  const saveLocationToCache = async (newLocation: LocationState) => {
    try {
      await AsyncStorage.setItem(LOCATION_CACHE_KEY, JSON.stringify(newLocation));
    } catch (err) {
      console.warn('Error caching location:', err);
    }
  };

  const updateLocation = async () => {
    try {
      setError(null);

      // Check permissions
      const { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        setError('Permission to access location was denied');
        return;
      }

      // Get location
      const currentLocation = await Location.getCurrentPositionAsync({
        accuracy: Location.Accuracy.Balanced,
      });

      const newLocation: LocationState = {
        latitude: currentLocation.coords.latitude,
        longitude: currentLocation.coords.longitude,
      };

      setLocation(newLocation);
      saveLocationToCache(newLocation);
    } catch (err) {
      setError('Error getting location');
      console.error('Location error:', err);
    }
  };

  useEffect(() => {
    let isMounted = true;

    const getLocation = async () => {
      try {
        // Try to load cached location first
        const hasCachedLocation = await loadCachedLocation();

        // If no valid cached location, get fresh location
        if (!hasCachedLocation) {
          await updateLocation();
        }
      } catch (err) {
        if (isMounted) {
          setError('Error getting location');
          setLocation(null);
        }
      }
    };

    getLocation();

    // Set up location updates
    let locationSubscription: Location.LocationSubscription | null = null;

    const startLocationUpdates = async () => {
      locationSubscription = await Location.watchPositionAsync(
        {
          accuracy: Location.Accuracy.Balanced,
          timeInterval: LOCATION_CACHE_DURATION,
          distanceInterval: 100, // Update if moved more than 100 meters
        },
        (position) => {
          const newLocation: LocationState = {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          };
          setLocation(newLocation);
          saveLocationToCache(newLocation);
        }
      );
    };

    startLocationUpdates();

    // Cleanup
    return () => {
      isMounted = false;
      if (locationSubscription) {
        locationSubscription.remove();
      }
    };
  }, []);

  return { location, error };
};
